const express = require('express');
const bcrypt = require('bcryptjs');

function createAccountDeletionRouter({ db }) {
  if (!db) throw new Error('db is required');

  const router = express.Router();

  router.post('/delete-account', express.json(), async (req, res) => {
    try {
      const sessionUserId = req.session?.userId;
      if (!sessionUserId) return res.status(401).json({ error: 'unauthorized' });

      const password = typeof req.body?.password === 'string' ? req.body.password : '';
      if (!password) return res.status(400).json({ error: 'password_required' });

      const user = await db.users.findById(sessionUserId);
      if (!user) return res.status(401).json({ error: 'unauthorized' });

      const ok = await bcrypt.compare(password, user.passwordHash);
      if (!ok) return res.status(403).json({ error: 'invalid_password' });

      await db.transaction(async (tx) => {
        await tx.auditLogs.insert({
          userId: user.id,
          action: 'account_deleted',
          ip: req.ip,
          userAgent: req.get('user-agent') || null,
          createdAt: new Date()
        });

        await tx.sessions.deleteByUserId(user.id);
        await tx.users.deleteById(user.id);
      });

      if (typeof req.session?.destroy === 'function') {
        await new Promise((resolve) => req.session.destroy(() => resolve()));
      }

      res.status(204).end();
    } catch (err) {
      res.status(500).json({ error: 'server_error' });
    }
  });

  return router;
}

